INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSHA$$, $$hsha00$$, $$House Committee on House Administration$$, $$house$$, $$standing$$, NULL, $$https://cha.house.gov/$$, $$The Committee on House Administration has legislative jurisdiction over the federal elections and the day-to-day operations of the House. The Committee's jurisdiction over federal elections requires it to consider proposals to amend federal election law and to monitor congressional elections across the United States. The Committee also sets budget authorizations for expenses of other House committees and members of Congress. It also oversees several federal organizations such as the Library of Congress and Smithsonian Institution.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSHA08$$, $$hsha08$$, $$Elections$$, $$house$$, $$subcommittee$$, $$HSHA$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSHM$$, $$hshm00$$, $$House Committee on Homeland Security$$, $$house$$, $$standing$$, NULL, $$https://homeland.house.gov/$$, $$The House Committee on Homeland Security has jurisdiction over matters related to national defense. It has six subcommittees on border and maritime security; counterterrorism and intelligence; cybersecurity and infrastructure protection; emergency preparedness, response, and communications; oversight and management efficiency; and transportation and protective security. The Committee was created in 2002 in the aftermath of the September 11th, 2001 attacks.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSHM12$$, $$hshm12$$, $$Emergency Management and Technology$$, $$house$$, $$subcommittee$$, $$HSHM$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
