INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSIF$$, $$hsif00$$, $$House Committee on Energy and Commerce$$, $$house$$, $$standing$$, NULL, $$https://energycommerce.house.gov/$$, $$The House Committee on Energy and Commerce has legislative jurisdiction on matters related to telecommunications, consumer protection, food and drug safety, public health research, environmental quality, energy policy, and interstate and foreign commerce. It oversees multiple cabinet-level Departments and independent agencies, including the Departments of Energy, Health and Human Services, Commerce, and Transportation, as well as the Environmental Protection Agency, the Federal Trade Commission, the Food and Drug Administration, and the Federal Communications Commission.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
