INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSED$$, $$hsed00$$, $$House Committee on Education and Workforce$$, $$house$$, $$standing$$, NULL, $$https://edlabor.house.gov/$$, $$The committee has legislative jurisdiction over matters related to higher and lower education, workforce development and protections, and health, employment, labor, and pensions.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSGO$$, $$hsgo00$$, $$House Committee on Oversight and Government Reform$$, $$house$$, $$standing$$, NULL, $$https://oversight.house.gov/$$, $$The committee oversees the federal government and all of its agencies to ensure efficiency, effectiveness, and accountability. The Committee oversees government operations, health care, information technology, interior, energy and environment, national security, and intergovernmental affairs.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSGO24$$, $$hsgo24$$, $$Government Operations$$, $$house$$, $$subcommittee$$, $$HSGO$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSJU$$, $$hsju00$$, $$House Committee on the Judiciary$$, $$house$$, $$standing$$, NULL, $$https://judiciary.house.gov/$$, $$The Committee on the Judiciary has jurisdiction over matters relating to the administration of justice in federal courts, administrative bodies, and law enforcement agencies. Its role in impeachment proceedings has also brought it much attention.  The committee’s jurisdiction also includes a range of issues such as bankruptcy, espionage, terrorism, the protection of civil liberties, constitutional amendments, and more. The Committee oversees the Departments of Justice and Homeland Security.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSJU01$$, $$hsju01$$, $$Immigration Integrity, Security, and Enforcement$$, $$house$$, $$subcommittee$$, $$HSJU$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSAG03$$, $$hsag03$$, $$Nutrition and Foreign Agriculture$$, $$house$$, $$subcommittee$$, $$HSAG$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.941+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSAP$$, $$hsap00$$, $$House Committee on Appropriations$$, $$house$$, $$standing$$, NULL, $$https://appropriations.house.gov/$$, $$The House Committee on Appropriations is responsible for legislation allocating federal funds prior to expenditure from the treasury. Appropriations are generally limited to the levels set by the Budget Resolution drafted by the House Committee on the Budget. The Committee is also responsible for supplemental spending bills, which are sometimes needed in the middle of a fiscal year to compensate for emergency expenses.$$, FALSE, NULL, $$2026-05-21T00:02:52.941+00:00$$, TRUE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSAP01$$, $$hsap01$$, $$Agriculture, Rural Development, Food and Drug Administration, and Related Agencies$$, $$house$$, $$subcommittee$$, $$HSAP$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.941+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SSFR01$$, $$ssfr01$$, $$Europe and Regional Security Cooperation$$, $$senate$$, $$subcommittee$$, $$SSFR$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SSFR09$$, $$ssfr09$$, $$Africa and Global Health Policy$$, $$senate$$, $$subcommittee$$, $$SSFR$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SSGA$$, $$ssga00$$, $$Senate Committee on Homeland Security and Governmental Affairs$$, $$senate$$, $$standing$$, NULL, $$http://www.hsgac.senate.gov/$$, $$The Senate Committee on Homeland Security and Governmental Affairs is the Senate’s primary oversight committee with broad jurisdiction over government operations generally and the Department of Homeland Security in particular. Its primary responsibilities are to study the efficiency, economy, and effectiveness of all agencies and departments of the federal government; evaluate the effects of laws enacted to reorganize the legislative and executive branches of government; and study the intergovernmental relationships between the U.S. and states and municipalities, and between the U.S. and international organizations of which the U.S. is a member.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSAP19$$, $$hsap19$$, $$Commerce, Justice, Science, and Related Agencies$$, $$house$$, $$subcommittee$$, $$HSAP$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.941+00:00$$, FALSE) ON CONFLICT DO NOTHING;
