INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSWM$$, $$hswm00$$, $$House Committee on Ways and Means$$, $$house$$, $$standing$$, NULL, $$https://waysandmeans.house.gov/$$, $$The Committee on Ways and Means is the chief tax-writing committee in the House of Representatives. The Committee derives a large share of its jurisdiction from Article I, Section VII of the U.S. Constitution, which declares, “All Bills for raising Revenue shall originate in the House of Representatives.” The committee has jurisdiction over revenue and related issues such as tariffs, reciprocal trade agreements, and the bonded debt of the United States. It also oversees revenue-related aspects of the Social Security system, Medicare, and social services programs.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$HSWM02$$, $$hswm02$$, $$Health$$, $$house$$, $$subcommittee$$, $$HSWM$$, NULL, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
