INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$JSTX$$, $$jstx00$$, $$Joint Committee on Taxation$$, $$joint$$, $$joint$$, NULL, $$https://www.jct.gov$$, NULL, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SCNC$$, $$scnc00$$, $$United States Senate Caucus on International Narcotics Control$$, $$senate$$, $$senate$$, NULL, $$http://www.drugcaucus.senate.gov/$$, $$The Senate Caucus on International Narcotics Control was created to “monitor and encourage United States Government and private programs seeking to expand international cooperation against drug abuse and narcotics trafficking” and to “monitor and promote international compliance with narcotics control treaties.” As a formal organization of the U.S. Senate, the Caucus has the status of a standing committee. The Caucus exercises oversight on a wide range of issues, including international counternarcotics assistance and domestic drug prevention and treatment programs. The Caucus has held numerous hearings over the years and has issued a number of reports on U.S. narcotics control policy.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SLET$$, $$slet00$$, $$Senate Select Committee on Ethics$$, $$senate$$, $$senate$$, NULL, $$http://www.ethics.senate.gov/$$, $$The Senate Select Committee on Ethics is authorized to receive and investigate allegations of improper conduct which may reflect upon the Senate, violations of law, violations of the Senate Code of Official Conduct and violations of rules and regulations of the Senate; recommend disciplinary action; recommend additional Senate rules or regulations to insure proper standards of conduct; and report violations of law to the proper federal and state authorities.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SLIA$$, $$slia00$$, $$Senate Committee on Indian Affairs$$, $$senate$$, $$senate$$, NULL, $$http://www.indian.senate.gov/$$, $$The Senate Committee on Indian Affairs has jurisdiction to study the unique problems of American Indian, Native Hawaiian, and Alaska Native peoples and to propose legislation to alleviate these difficulties. These issues include, but are not limited to, Indian education, economic development, land management, trust responsibilities, health care, and claims against the United States. Additionally, all legislation proposed by Members of the Senate that specifically pertains to American Indians, Native Hawaiians, or Alaska Natives is under the jurisdiction of the Committee.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SSAF$$, $$ssaf00$$, $$Senate Committee on Agriculture, Nutrition, and Forestry$$, $$senate$$, $$standing$$, NULL, $$http://www.agriculture.senate.gov/$$, $$The Senate Committee on Agriculture has legislative jurisdiction over agriculture, food, and nutrition.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, FALSE) ON CONFLICT DO NOTHING;
