INSERT INTO public.hill_committees (thomas_id, system_code, name, chamber, type, parent_thomas_id, url, jurisdiction, is_priority, notes, last_synced_at, show_on_summary) VALUES ($$SSAS$$, $$ssas00$$, $$Senate Committee on Armed Services$$, $$senate$$, $$standing$$, NULL, $$http://www.armed-services.senate.gov/$$, $$The Senate Committee on Armed Services has legislative jurisdiction over military and defense.$$, FALSE, NULL, $$2026-05-21T00:02:52.942+00:00$$, TRUE) ON CONFLICT DO NOTHING;
